import React, { useState, useEffect } from 'react';
import axios from 'axios';
import Sidebar from './Sidebar';
import CreateForm from './CreateForm';

const AdminPanel = () => {
  const [activeTab, setActiveTab] = useState('create');
  const [postType, setPostType] = useState('blog');
  const [category, setCategory] = useState('Electronics');
  const [formData, setFormData] = useState({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
  const [file, setFile] = useState(null);
  const [items, setItems] = useState([]);
  const [inquiries, setInquiries] = useState([]);
  const [isEditing, setIsEditing] = useState(false);
  const [editId, setEditId] = useState(null);

  const fetchItems = async () => {
    try {
      const url = postType === 'job' ? 'http://localhost:5001/api/jobs' : `http://localhost:5001/api/blog/${category}`;
      const res = await axios.get(url);
      setItems(Array.isArray(res.data) ? res.data : []);
    } catch (err) { setItems([]); }
  };

  const fetchInquiries = async () => {
    try {
      const res = await axios.get('http://localhost:5001/api/contact');
      setInquiries(Array.isArray(res.data) ? res.data : (res.data.inquiries || []));
    } catch (err) { setInquiries([]); }
  };

  useEffect(() => {
    if (activeTab === 'manage') fetchItems();
    if (activeTab === 'inquiries') fetchInquiries();
  }, [activeTab, postType, category]);

  const handleEdit = (item) => {
    setIsEditing(true);
    setEditId(item._id);
    setActiveTab('create');
    setFormData({ title: item.title, description: item.description || '', loc: item.loc || '', salary: item.salary || '', type: item.type || 'On-site' });
    if (item.category) setCategory(item.category);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (isEditing) {
        const endpoint = postType === 'job' ? `jobs/${editId}` : `blog/${editId}`;
        await axios.patch(`http://localhost:5001/api/admin/${endpoint}`, formData);
        alert("Updated!");
      } else {
        if (postType === 'job') {
          await axios.post('http://localhost:5001/api/admin/jobs', formData);
        } else {
          const data = new FormData();
          data.append('category', category); data.append('title', formData.title);
          data.append('description', formData.description); if (file) data.append('image', file);
          await axios.post('http://localhost:5001/api/admin/blog', data);
        }
        alert("Published!");
      }
      setFormData({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
      setIsEditing(false);
    } catch (err) { alert("Failed!"); }
  };

  const handleDelete = async (id, type) => {
    if (window.confirm("Delete?")) {
      const endpoint = type === 'inquiry' ? 'contact' : (postType === 'job' ? 'jobs' : 'blog');
      await axios.delete(`http://localhost:5001/api/admin/${endpoint}/${id}`);
      type === 'inquiry' ? fetchInquiries() : fetchItems();
    }
  };

  return (
    <div className="flex min-h-screen bg-gray-50 pt-10 font-sans">
      <Sidebar 
        activeTab={activeTab} setActiveTab={setActiveTab} 
        setIsEditing={setIsEditing} postType={postType} 
        setPostType={setPostType} category={category} setCategory={setCategory} 
      />

      <div className="flex-1 ml-80 p-12">
        {activeTab === 'create' && (
          <CreateForm 
            isEditing={isEditing} handleSubmit={handleSubmit} 
            postType={postType} formData={formData} 
            setFormData={setFormData} setFile={setFile} 
          />
        )}

        {activeTab === 'manage' && (
          <div className="max-w-4xl bg-white rounded-[3rem] p-12 shadow-sm border border-gray-100">
            <h1 className="text-4xl font-black italic text-gray-900 mb-10 tracking-tighter">Active Repository</h1>
            <div className="space-y-4">
              {items.map(item => (
                <div key={item._id} className="flex items-center justify-between p-7 bg-gray-50 rounded-[2.5rem] border border-gray-100">
                  <div>
                    <h3 className="font-black text-xl">{item.title}</h3>
                    <span className="text-orange-500 text-[10px] font-black uppercase tracking-widest">{item.loc || item.category}</span>
                  </div>
                  <div className="flex gap-3">
                    <button onClick={() => handleEdit(item)} className="bg-gray-200 px-6 py-2 rounded-xl font-black text-[10px]">EDIT</button>
                    <button onClick={() => handleDelete(item._id, 'item')} className="bg-red-50 text-red-500 px-6 py-2 rounded-xl font-black text-[10px]">DELETE</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'inquiries' && (
          <div className="max-w-5xl bg-white rounded-[3rem] p-12 shadow-sm border border-gray-100">
             {/* Inquiry Mapping Logic */}
             {inquiries.map(iq => (
               <div key={iq._id} className="p-8 bg-gray-100 rounded-[2.5rem] mb-4">
                 <h3 className="text-2xl font-black">{iq.fullName}</h3>
                 <p className="text-orange-600 font-bold">{iq.email}</p>
                 <button onClick={() => handleDelete(iq._id, 'inquiry')} className="text-red-500 font-black text-[10px] uppercase mt-4">Delete Record</button>
               </div>
             ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;
